#include<bits/stdc++.h>
using namespace std;
struct node
{
    int lson,rson,sum;
}t[10000010];
int root[100010],a[100010],cnt,n,m;
int add(int &x,int pos,int val,int l=0,int r=1000000000)
{
    int now=++cnt;
    if(x==0)
    {
        t[x].lson=t[x].rson=0;
        t[x].sum=0;
    }
    t[now]=t[x];
    t[now].sum+=val;
    if(l==r)
    {
        return now;
    }
    int mid=(l+r)>>1;
    if(pos<=mid)
    {
        t[now].lson=add(t[x].lson,pos,val,l,mid);
    }
    else
    {
        t[now].rson=add(t[x].rson,pos,val,mid+1,r);
    }
    return now;
}
int query(int &u,int &v,int L,int R,int l=0,int r=1000000000)
{
    if(L>r||l>R)
    {
        return 0;
    }
    if(!u)
    {
        t[u].lson=t[u].rson=0;
        t[u].sum=0;
    }
    if(!v)
    {
        t[v].lson=t[v].rson=0;
        t[v].sum=0;
    }
    if(L<=l&&r<=R)
    {
        return t[v].sum-t[u].sum;
    }
    int mid=(l+r)>>1,ans=0;
    if(L<=mid)
    {
        ans+=query(t[u].lson,t[v].lson,L,R,l,mid);
    }
    if(R>mid)
    {
        ans+=query(t[u].rson,t[v].rson,L,R,mid+1,r);
    }
    return ans;
}
struct st
{
    int f[100010][21],lg[100010];
    void init()
    {
        lg[1]=0;
        for(int i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(int i=1;i<=n;i++)
        {
            f[i][0]=i;
        }
        for(int j=1;j<=lg[n];j++)
        {
            for(int i=1;i<=n-(1<<j)+1;i++)
            {
                int p=f[i][j-1],q=f[i+(1<<(j-1))][j-1];
                f[i][j]=(a[p]>=a[q]?p:q);
            }
        }
    }
    int getmax(int l,int r)
    {
        int tmp=lg[r-l+1];
        int p=f[l][tmp],q=f[r-(1<<tmp)+1][tmp];
        return (a[p]>=a[q]?p:q);
    }
}ST;
long long ans;
void dfs(int l,int r)
{
    if(l>r)
    {
        return;
    }
    if(l==r)
    {
        ans+=(a[l]==1);
        // printf("dfs(%d,%d) ans=%lld\n",l,r,ans);
        return;
    }
    int mid=ST.getmax(l,r);
    if(mid-l+1<=r-mid)
    {
        for(int i=l;i<=mid;i++)
        {
            int tmp=query(root[mid-1],root[r],1,a[mid]/a[i]);
            ans+=tmp;
            // printf("i=%d l=%d r=%d mid=%d tmp=%d\n",i,l,r,mid,tmp);
        }
    }
    else
    {
        for(int i=mid;i<=r;i++)
        {
            int tmp=query(root[l-1],root[mid],1,a[mid]/a[i]);
            ans+=tmp;
            // printf("i=%d l=%d r=%d mid=%d tmp=%d\n",i,l,r,mid,tmp);
        }
    }
    // printf("dfs(%d,%d) ans=%lld\n",l,r,ans);
    dfs(l,mid-1);
    dfs(mid+1,r);
    // printf("dfs(%d,%d) ans=%lld\n",l,r,ans);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        root[i]=add(root[i-1],a[i],1);
    }
    ST.init();
    dfs(1,n);
    printf("%lld",ans);
    return 0;
}
